// Agrega Stripe (ingresos del mes, num. cuotas) + Wise (saldo) en el formato de finance_snapshots.
const stripeInvoices = $items('Stripe \u00b7 facturas pagadas del mes').map(i => i.json);
const wiseBalance = $items('Wise \u00b7 saldo de la cuenta')[0]?.json ?? {};

const incomeMonthCents = stripeInvoices.reduce((acc, inv) => acc + (inv.amount_paid ?? 0), 0);
const membersCount = new Set(stripeInvoices.map(inv => inv.customer)).size;
const balanceCents = Math.round((wiseBalance.amount?.value ?? 0) * 100);

return [{
  json: {
    taken_at: new Date().toISOString(),
    balance_cents: balanceCents,
    income_month_cents: incomeMonthCents,
    members_count: membersCount,
  },
}];
